from flask import Flask, request, jsonify
from flask_login import login_required, current_user

app = Flask(__name__)

@app.route('/update_profile', methods=['POST'])
@login_required
def update_profile():
    data = request.json
    allowed_fields = {'email', 'username', 'account_type', 'credits', 'referral_code', 'verified_status'}
    updatable_fields = {key: value for key, value in data.items() if key in allowed_fields}

    # Server-side authorization checks (pseudo-code)
    if not current_user.has_permission('update_profile'):
        return jsonify({'error': 'Unauthorized'}), 403

    # Example: Check if user can update each field
    for field in updatable_fields:
        if not current_user.can_update_field(field):
            return jsonify({'error': f'Unauthorized to update {field}'}), 403

    # Update user profile
    for field, value in updatable_fields.items():
        setattr(current_user, field, value)

    # Save changes to the database (pseudo-code)
    # db.session.commit()

    return jsonify({'success': 'Profile updated successfully'})

if __name__ == '__main__':
    app.run(debug=True)